def gen(rng, size):
    n = max(1, min(size, 100))
    vals = list(range(n))
    rng.shuffle(vals)
    # build a random binary tree as nested [val, left, right]
    def build(items):
        if not items:
            return None
        root = items[0]
        rest = items[1:]
        k = rng.randint(0, len(rest))
        left = build(rest[:k])
        right = build(rest[k:])
        return [root, left, right]
    tree = build(vals)
    def to_level(t):
        out = []
        q = [t]
        while q:
            nxt = []
            for node in q:
                if node is None:
                    out.append(None)
                else:
                    out.append(node[0])
                    nxt.append(node[1])
                    nxt.append(node[2])
            q = nxt
        while out and out[-1] is None:
            out.pop()
        return out
    def flipped_copy(t):
        if t is None:
            return None
        l = flipped_copy(t[1])
        r = flipped_copy(t[2])
        if rng.random() < 0.5:
            return [t[0], r, l]
        return [t[0], l, r]
    a = to_level(tree)
    if rng.random() < 0.5:
        b = to_level(flipped_copy(tree))
    else:
        b = to_level(flipped_copy(tree))
        if b:
            idx = rng.randrange(len(b))
            if b[idx] is None:
                b[idx] = rng.randint(0, 99)
            else:
                b[idx] = (b[idx] + 1) % 100
    if not a:
        a = []
    if not b:
        b = []
    return [a, b]

