class Solution:
    def flipEquiv(self, root1, root2):
        def canon(node):
            if node is None:
                return (0,)
            l = canon(node.left)
            r = canon(node.right)
            lo, hi = (l, r) if l <= r else (r, l)
            return (1, node.val, lo, hi)
        return canon(root1) == canon(root2)

